const now = new Date();
const nowIso = now.toISOString();
const dailyCap = Number($env.DAILY_SEND_CAP || 10);
const maxFollowups = Number($env.MAX_FOLLOWUPS || 2);
const servicePrompt = String($env.OUTREACH_SYSTEM_PROMPT || `You are writing Telegram outreach for ${$env.OUTREACH_SENDER_NAME || 'OutreachTeam'}. Never invent facts.`).trim();
const apiKey = String($env.OPENAI_API_KEY || '').trim();
const safeText = (v, max = 300) => String(v ?? '').replace(/[\u0000-\u001F\u007F]/g, ' ').replace(/[<>]/g, '').replace(/\s+/g, ' ').trim().slice(0, max);

const leadRows = $items('Read Leads', 0, 0).map(i => i.json || {});
const stateRows = items.map(i => i.json || {}).filter(r => String(r.lead_id || '').trim());
const stateMap = new Map(stateRows.map(r => [String(r.lead_id).trim(), r]));

const normalizeLead = (row) => {
  const leadId = String(row.lead_id || '').trim();
  if (!leadId) return null;
  const username = String(row.telegram_username || '').replace(/^@/, '').trim();
  if (!username) return null;
  const status = String(row.status || 'NEW').toUpperCase().trim() || 'NEW';
  const followupCount = Number(row.followup_count || 0);
  const nextFollowupAt = row.next_followup_at ? new Date(row.next_followup_at) : null;
  const dueFollowup = status === 'FOLLOWUP_DUE' && nextFollowupAt && !Number.isNaN(nextFollowupAt.getTime()) && nextFollowupAt <= now;
  const eligible = (status === 'NEW' || dueFollowup) && !['DNC', 'NOT_INTERESTED', 'REPLIED'].includes(status) && followupCount < maxFollowups;
  return {
    lead_id: leadId,
    name: String(row.name || ''),
    telegram_username: username,
    company: String(row.company || ''),
    role: String(row.role || ''),
    source_url: String(row.source_url || ''),
    status,
    last_contacted_at: String(row.last_contacted_at || ''),
    next_followup_at: String(row.next_followup_at || ''),
    followup_count: followupCount,
    due_followup: dueFollowup,
    eligible,
  };
};

const leads = leadRows.map(normalizeLead).filter(Boolean);
const candidates = leads
  .filter(r => r.eligible)
  .sort((a, b) => {
    if (a.due_followup && !b.due_followup) return -1;
    if (!a.due_followup && b.due_followup) return 1;
    return a.lead_id.localeCompare(b.lead_id);
  })
  .slice(0, dailyCap);

async function fetchResearch(url) {
  if (!url) return '';
  try {
    const ctl = new AbortController();
    const t = setTimeout(() => ctl.abort(), 8000);
    const res = await fetch(url, { signal: ctl.signal, headers: { 'User-Agent': 'Mozilla/5.0 OutreachBot/1.0' } });
    clearTimeout(t);
    if (!res.ok) return '';
    const html = await res.text();
    const title = (html.match(/<title[^>]*>([\s\S]*?)<\/title>/i)?.[1] || '').replace(/\s+/g, ' ').trim();
    const h1 = (html.match(/<h1[^>]*>([\s\S]*?)<\/h1>/i)?.[1] || '').replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();
    const meta = (html.match(/<meta[^>]*name=["']description["'][^>]*content=["']([\s\S]*?)["'][^>]*>/i)?.[1] || '').replace(/\s+/g, ' ').trim();
    return [title, h1, meta].filter(Boolean).slice(0, 2).join(' | ').slice(0, 320);
  } catch {
    return '';
  }
}

async function callOpenAi(system, user) {
  if (!apiKey || apiKey.startsWith('replace-with-')) return '';
  const ctl = new AbortController();
  const t = setTimeout(() => ctl.abort(), 20000);
  try {
    const res = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      signal: ctl.signal,
      headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        temperature: 0.6,
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: user },
        ],
      }),
    });
    if (!res.ok) return '';
    const data = await res.json();
    return String(data?.choices?.[0]?.message?.content || '').replace(/\s+/g, ' ').trim();
  } catch {
    return '';
  } finally {
    clearTimeout(t);
  }
}

async function draftMessage(lead, state, researchSnippet) {
  const isFollowup = !!lead.due_followup;
  const hardRules = `Hard rules:\n- Do not invent company/role details.\n- If company/role/research is empty, keep message generic.\n- Max 450 characters.\n- One question maximum.\n- Human tone.`;
  const userPrompt = isFollowup
    ? `Create a short follow-up Telegram message.\nLead name: ${lead.name}\nCompany: ${lead.company}\nRole: ${lead.role}\nResearch snippet: ${researchSnippet}\nLast message sent: ${state.last_sent_type || ''}\nMemory summary: ${state.memory_summary || ''}\nLast reply: ${state.last_reply_received || ''}\n${hardRules}`
    : `Create a first outreach Telegram message.\nLead name: ${lead.name}\nCompany: ${lead.company}\nRole: ${lead.role}\nResearch snippet: ${researchSnippet}\n${hardRules}`;
  const generated = await callOpenAi(servicePrompt, userPrompt);
  if (generated) return generated.slice(0, 450);
  return (isFollowup
    ? `Hi ${lead.name}, quick follow-up in case this is still relevant. If useful I can send a concise tailored note. Interested?`
    : `Hi ${lead.name}, sharing a practical idea that may support your growth goals. If helpful, I can send a concise tailored plan here. Interested?`).replace(/\s+/g, ' ').trim().slice(0, 450);
}

const out = [];
for (const lead of candidates) {
  const state = stateMap.get(lead.lead_id) || {};
  const research = await fetchResearch(lead.source_url);
  const draft = await draftMessage(lead, state, research);
  const leadToken = String(lead.lead_id).replace(/[^a-zA-Z0-9_-]/g, '').slice(0, 48);
  const opsMessage = [
    'Approval Required',
    `lead_id: ${safeText(lead.lead_id, 120)}`,
    `name: ${safeText(lead.name || 'N/A', 120)}`,
    `target: @${safeText(lead.telegram_username, 120)}`,
    `research: ${safeText(research || '-', 240)}`,
    '',
    'Draft:',
    safeText(draft, 520),
    '',
    `Text commands: approve ${safeText(lead.lead_id, 120)} | edit ${safeText(lead.lead_id, 120)} <feedback> | skip ${safeText(lead.lead_id, 120)} | dnc ${safeText(lead.lead_id, 120)}`,
  ].join('\n');

  out.push({
    json: {
      lead_id: lead.lead_id,
      name: lead.name,
      telegram_username: lead.telegram_username,
      company: lead.company,
      role: lead.role,
      source_url: lead.source_url,
      status: 'NEEDS_APPROVAL',
      last_contacted_at: lead.last_contacted_at || '',
      next_followup_at: lead.next_followup_at || '',
      followup_count: lead.followup_count,
      telegram_chat_id: String(state.telegram_chat_id || ''),
      draft_message: draft,
      research_snippet: research,
      memory_summary: String(state.memory_summary || ''),
      approval_feedback: '',
      last_reply_received: String(state.last_reply_received || ''),
      last_reply_at: String(state.last_reply_at || ''),
      last_idempotency_key: String(state.last_idempotency_key || ''),
      last_sent_type: String(state.last_sent_type || ''),
      last_error: String(state.last_error || ''),
      last_error_at: String(state.last_error_at || ''),
      message_history: String(state.message_history || ''),
      updated_at: nowIso,
      ops_message: opsMessage,
      cb_approve: `approve:${leadToken}`,
      cb_edit: `edit:${leadToken}`,
      cb_skip: `skip:${leadToken}`,
      cb_dnc: `dnc:${leadToken}`,
    }
  });
}

return out;
